function encrypt($data, $key = 'key123') {
    $encryptedData = '';
    foreach (str_split($data) as $char) {
        $encryptedChar = chr(ord($char) ^ ord($key[fmod(strlen($char), strlen($key))]));
        $encryptedData .= $encryptedChar;
    }
    return base64_encode($encryptedData);
}

function decrypt($data, $key = 'key123') {
    $decryptedData = base64_decode($data);
    $decryptedChars = str_split($decryptedData);
    $keyChars = str_split($key);

    $decryptedEncodedData = '';
    foreach ($decryptedChars as $charIndex => $encryptedChar) {
        $decryptedChar = chr(ord($encryptedChar) ^ ord($keyChars[fmod($charIndex, strlen($key))]));
        $decryptedEncodedData .= $decryptedChar;
    }

    return $decryptedEncodedData;
}